05-13 14:53:57','2025-05-13 14:53:57','src/images/products/uploads/6822ec85dc445_Screenshot 2025-05-13 145312.png','src/images/products/uploads/6822ec85dc212_Screenshot 2025-05-13 145312.png',NULL,'src/images/products/uploads/6822ec85dc597_Screenshot 2025-05-13 145312.png',0),(21,'CREAM02','SKINEVER SPF50+ UV Whitening ','Lightweight texture, hydrating and skin-friendly, a good partner with makeup',NULL,NULL,450.00,NULL,4,NULL,NULL,NULL,NULL,1,1,'2025-05-13 14:55:25','2025-06-15 14:46:00','src/images/products/uploads/6822ecdd2469f_Screenshot 2025-05-13 145513.png','src/images/products/uploads/6822ecdd2449d_Screenshot 2025-05-13 145513.png',NULL,'src/images/products/uploads/6822ecdd247f8_Screenshot 2025-05-13 145513.png',0),(22,'LOTION02','APLB Glutathione Niacinamide Body Lotion 300ml','Complex patented ingredients make it a premium Body Lotion that provides rich nutrition and deep moisture to the skin, making it lively and moisturized.',NULL,NULL,550.00,NULL,5,NULL,NULL,NULL,NULL,1,0,'2025-05-13 14:57:00','2025-05-13 14:57:00','src/images/products/uploads/6822ed3c9472e_Screenshot 2025-05-13 145644.png','src/images/products/uploads/6822ed3c94572_Screenshot 2025-05-13 145644.png',NULL,'src/images/products/uploads/6822ed3c94854_Screenshot 2025-05-13 145644.png',0),(23,'UNDS02','Organic - Skin Japan Intensive Whitening Arm Deodorant Spray','Spray Intense White provides long lasting natural protection from body odor and gives a feeling of freshness and dryness that last all day.',NULL,NULL,190.00,NULL,6,NULL,NULL,NULL,NULL,1,0,'2025-05-13 14:58:14','2025-05-13 14:58:14','src/images/products/uploads/6822ed860fca9_Screenshot 2025-05-13 145800.png','src/images/products/uploads/6822ed860fa72_Screenshot 2025-05-13 145800.png',NULL,'src/images/products/uploads/6822ed860fe04_Screenshot 2025-05-13 145800.png',0);
